using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Design;using Microsoft.EntityFrameworkCore.Metadata.Builders;using Microsoft.Extensions.Configuration;using Todos.Domain;
namespace Todos.Persistence;
/** <summary>Todos context.</summary> */ public sealed class TodosDbContext(DbContextOptions<TodosDbContext> o):DbContext(o){/** <summary>Schema.</summary> */ public const string Schema="todos";/** <summary>Items.</summary> */ public DbSet<TodoItem> Items=>Set<TodoItem>();/** <inheritdoc/> */ protected override void OnModelCreating(ModelBuilder b){b.HasDefaultSchema(Schema);b.ApplyConfigurationsFromAssembly(typeof(TodosDbContext).Assembly);}}
/** <summary>Todo mapping.</summary> */ public sealed class TodoConfiguration:IEntityTypeConfiguration<TodoItem>{/** <inheritdoc/> */ public void Configure(EntityTypeBuilder<TodoItem>b){b.ToTable("todo_items");b.HasKey(x=>x.Id);b.Property(x=>x.Title).HasMaxLength(300).IsRequired();b.Property(x=>x.Status).HasConversion<string>();b.Property(x=>x.Priority).HasConversion<string>();b.Property(x=>x.Notes).HasMaxLength(2000);b.HasIndex(x=>x.DueDate);b.HasIndex(x=>x.Status);}}
/** <summary>Repository.</summary> */ public sealed class TodoRepository(TodosDbContext db):ITodoRepository{/** <inheritdoc/> */ public Task<TodoItem?> GetByIdAsync(Guid id,CancellationToken ct)=>db.Items.SingleOrDefaultAsync(x=>x.Id==id,ct);/** <inheritdoc/> */ public void Add(TodoItem i)=>db.Items.Add(i);/** <inheritdoc/> */ public void Remove(TodoItem i)=>db.Items.Remove(i);/** <inheritdoc/> */ public async Task SaveChangesAsync(CancellationToken ct)=>await db.SaveChangesAsync(ct);}
/** <summary>Tooling factory.</summary> */ public sealed class TodosDbContextFactory:IDesignTimeDbContextFactory<TodosDbContext>{/** <inheritdoc/> */ public TodosDbContext CreateDbContext(string[] args){var c=new ConfigurationBuilder().SetBasePath(Directory.GetCurrentDirectory()).AddJsonFile("appsettings.json",true).AddEnvironmentVariables().Build();var s=c.GetConnectionString("Todos")??c.GetConnectionString("Default")??"Host=localhost;Database=alfaris;Username=postgres;Password=postgres";return new(new DbContextOptionsBuilder<TodosDbContext>().UseNpgsql(s,x=>x.MigrationsHistoryTable("__ef_migrations_history",TodosDbContext.Schema)).Options);}}
